import{_ as e,a as t,b as o,c as i,d,e as r}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as n,o as p,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Dodawanie kanału Dropbox","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/upload/dropbox.md","filePath":"pl-PL/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"pl-PL/upload/dropbox.md"};function k(b,a,h,u,z,w){return p(),l("div",null,[...a[0]||(a[0]=[s('<h1 id="dodawanie-kanału-dropbox" tabindex="-1">Dodawanie kanału Dropbox <a class="header-anchor" href="#dodawanie-kanału-dropbox" aria-label="Permalink to &quot;Dodawanie kanału Dropbox&quot;">​</a></h1><h2 id="co-przygotowac-przed-rozpoczeciem" tabindex="-1">Co przygotować przed rozpoczęciem <a class="header-anchor" href="#co-przygotowac-przed-rozpoczeciem" aria-label="Permalink to &quot;Co przygotować przed rozpoczęciem&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Wymaganie</th><th>Dlaczego jest potrzebne</th></tr></thead><tbody><tr><td>Konto Dropbox</td><td>Do logowania i autoryzacji aplikacji</td></tr><tr><td>Aplikacja Dropbox</td><td>Do wygenerowania <code>App Key</code> i <code>App Secret</code></td></tr><tr><td>Domena ImgBed</td><td>Do URI przekierowania OAuth</td></tr><tr><td>Dostępne miejsce Dropbox</td><td>Właściwe miejsce przechowywania plików</td></tr></tbody></table><h2 id="konfiguracja" tabindex="-1">Konfiguracja <a class="header-anchor" href="#konfiguracja" aria-label="Permalink to &quot;Konfiguracja&quot;">​</a></h2><h3 id="krok-1-utworz-aplikacje-dropbox" tabindex="-1">Krok 1: Utwórz aplikację Dropbox <a class="header-anchor" href="#krok-1-utworz-aplikacje-dropbox" aria-label="Permalink to &quot;Krok 1: Utwórz aplikację Dropbox&quot;">​</a></h3><ol><li>Otwórz Dropbox App Console:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>Utwórz nową aplikację.</li><li>Jako typ dostępu wybierz:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>Nadaj aplikacji rozpoznawalną nazwę, np. <code>imgbed-app</code>.</li><li>Po utworzeniu otwórz stronę szczegółów aplikacji.</li></ol><p>Zalecany typ dostępu:</p><table tabindex="0"><thead><tr><th>Typ dostępu</th><th>Rekomendacja</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>Zalecany. Pasuje do sposobu, w jaki ImgBed zapisuje pliki.</td></tr><tr><td><code>Full Dropbox</code></td><td>Niezalecany. ImgBed nie potrzebuje pełnego dostępu do konta.</td></tr></tbody></table><p><img src="'+e+'" alt="Tworzenie aplikacji Dropbox" loading="lazy"></p><h3 id="krok-2-dodaj-redirect-uri" tabindex="-1">Krok 2: Dodaj Redirect URI <a class="header-anchor" href="#krok-2-dodaj-redirect-uri" aria-label="Permalink to &quot;Krok 2: Dodaj Redirect URI&quot;">​</a></h3><p>Na stronie szczegółów aplikacji Dropbox znajdź ustawienia OAuth lub Redirect URI i dodaj:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>Jeśli używasz panelu administracyjnego z kilku domen, dodaj każdy pasujący callback URL.</p><p><img src="'+t+'" alt="Konfiguracja Redirect URI" loading="lazy"></p><h3 id="krok-3-skonfiguruj-uprawnienia-aplikacji" tabindex="-1">Krok 3: Skonfiguruj uprawnienia aplikacji <a class="header-anchor" href="#krok-3-skonfiguruj-uprawnienia-aplikacji" aria-label="Permalink to &quot;Krok 3: Skonfiguruj uprawnienia aplikacji&quot;">​</a></h3><p>Otwórz kartę <code>Permissions</code> i włącz co najmniej te scope:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Wymagany</th><th>Cel</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Wymagany</td><td>Czyta informacje o koncie i limicie</td></tr><tr><td><code>files.metadata.read</code></td><td>Wymagany</td><td>Czyta metadane plików i katalogów do kontroli ścieżek</td></tr><tr><td><code>files.metadata.write</code></td><td>Wymagany</td><td>Tworzy katalogi i zapisuje metadane</td></tr><tr><td><code>files.content.write</code></td><td>Wymagany</td><td>Przesyła pliki. Brak tego scope powoduje <code>required scope &#39;files.content.write&#39;</code>.</td></tr><tr><td><code>files.content.read</code></td><td>Zalecany</td><td>Pozwala pobierać, podglądać i tworzyć tymczasowe linki plików</td></tr></tbody></table><p>Po wybraniu scope kliknij <code>Submit</code> na dole strony.</p><p><img src="'+o+'" alt="Dodawanie uprawnień" loading="lazy"></p><p>Ważne:</p><table tabindex="0"><thead><tr><th>Sytuacja</th><th>Co zrobić</th></tr></thead><tbody><tr><td>Zmieniono scope</td><td>Uruchom autoryzację tokenu ponownie i pobierz nowy <code>Refresh Token</code>.</td></tr><tr><td>Nie wykonano ponownej autoryzacji</td><td>Stary token nie dostanie nowych uprawnień, więc upload może nadal się nie udawać.</td></tr></tbody></table><h3 id="krok-4-skopiuj-dane-aplikacji" tabindex="-1">Krok 4: Skopiuj dane aplikacji <a class="header-anchor" href="#krok-4-skopiuj-dane-aplikacji" aria-label="Permalink to &quot;Krok 4: Skopiuj dane aplikacji&quot;">​</a></h3><p>Zapisz te dwie wartości ze strony aplikacji Dropbox:</p><table tabindex="0"><thead><tr><th>Pole Dropbox</th><th>Pole ImgBed</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="krok-5-wypełnij-kanał-dropbox" tabindex="-1">Krok 5: Wypełnij kanał Dropbox <a class="header-anchor" href="#krok-5-wypełnij-kanał-dropbox" aria-label="Permalink to &quot;Krok 5: Wypełnij kanał Dropbox&quot;">​</a></h3><p>W Ustawieniach przesyłania wybierz <code>Dropbox</code> i wypełnij:</p><table tabindex="0"><thead><tr><th>Pole ImgBed</th><th>Co wpisać</th></tr></thead><tbody><tr><td>Nazwa kanału</td><td>Czytelna nazwa, np. <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>Dropbox <code>App key</code></td></tr><tr><td>App Secret</td><td>Dropbox <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>Na razie zostaw puste</td></tr><tr><td>Katalog główny</td><td>Opcjonalnie. Domyślnie <code>imgbed</code>.</td></tr><tr><td>Notatka</td><td>Opcjonalnie</td></tr></tbody></table><p><img src="'+i+'" alt="Pobieranie tokenu" loading="lazy"></p><h3 id="krok-6-pobierz-refresh-token" tabindex="-1">Krok 6: Pobierz Refresh Token <a class="header-anchor" href="#krok-6-pobierz-refresh-token" aria-label="Permalink to &quot;Krok 6: Pobierz Refresh Token&quot;">​</a></h3><ol><li>W ImgBed kliknij <code>Get Token</code>.</li><li>Zaloguj się na konto Dropbox, które chcesz podłączyć.</li><li>Zatwierdź autoryzację.</li><li>Strona callback pokaże <code>Refresh Token</code>.</li><li>Skopiuj go.</li><li>Wróć do ImgBed i wklej go w polu <code>Refresh Token</code>.</li></ol><p><img src="'+d+'" alt="Kopiowanie tokenu" loading="lazy"></p><h2 id="jak-sprawdzic" tabindex="-1">Jak sprawdzić <a class="header-anchor" href="#jak-sprawdzic" aria-label="Permalink to &quot;Jak sprawdzić&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kontrola</th><th>Oczekiwany wynik</th></tr></thead><tbody><tr><td>Karta kanału</td><td>Kanał Dropbox pojawia się po zapisaniu.</td></tr><tr><td>Przełącznik kanału</td><td>Kanał można włączyć.</td></tr><tr><td>Token zapisany</td><td>Strona szczegółów pokazuje, że <code>Refresh Token</code> został zapisany.</td></tr><tr><td>Upload testowy</td><td>Obraz testowy pojawia się w folderze aplikacji Dropbox.</td></tr></tbody></table><p>Jeśli limity pojemności są włączone, kliknij zapytanie o limit. Po udanym zapytaniu karta pokaże użyte miejsce, całkowite miejsce i czas ostatniej aktualizacji.</p><p><img src="'+r+`" alt="Zapytanie o limit zakończone powodzeniem" loading="lazy"></p><h2 id="rozwiazywanie-problemow" tabindex="-1">Rozwiązywanie problemów <a class="header-anchor" href="#rozwiazywanie-problemow" aria-label="Permalink to &quot;Rozwiązywanie problemów&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Rozwiązanie</th></tr></thead><tbody><tr><td>ImgBed zgłasza niepełną konfigurację</td><td>Sprawdź, czy <code>App Key</code>, <code>App Secret</code> i <code>Refresh Token</code> są wypełnione.</td></tr><tr><td>Autoryzacja działa, ale nie pojawia się <code>Refresh Token</code></td><td>Kliknij ponownie <code>Get Token</code> i upewnij się, że używany jest tryb offline.</td></tr><tr><td>Upload kończy się błędem <code>required scope &#39;files.content.write&#39;</code></td><td>Włącz <code>files.content.write</code>, kliknij <code>Submit</code>, a potem pobierz nowy <code>Refresh Token</code>.</td></tr><tr><td>Callback się nie udaje</td><td>Sprawdź, czy redirect URI to <code>https://your-domain.com/api/oauth/dropbox/callback</code>.</td></tr><tr><td>Pliki nie są znajdowane</td><td>Sprawdź, czy aplikacja Dropbox została utworzona w trybie <code>App folder</code>.</td></tr></tbody></table><h2 id="szybki-przebieg" tabindex="-1">Szybki przebieg <a class="header-anchor" href="#szybki-przebieg" aria-label="Permalink to &quot;Szybki przebieg&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Otwórz Dropbox App Console</span></span>
<span class="line"><span>-&gt; Utwórz aplikację</span></span>
<span class="line"><span>-&gt; Wybierz App folder access</span></span>
<span class="line"><span>-&gt; Dodaj https://your-domain.com/api/oauth/dropbox/callback</span></span>
<span class="line"><span>-&gt; Włącz account_info.read / files.metadata.read / files.metadata.write / files.content.write</span></span>
<span class="line"><span>-&gt; Opcjonalnie włącz files.content.read</span></span>
<span class="line"><span>-&gt; Kliknij Submit</span></span>
<span class="line"><span>-&gt; Skopiuj App Key i App Secret</span></span>
<span class="line"><span>-&gt; Wpisz je w ImgBed</span></span>
<span class="line"><span>-&gt; Kliknij Get Token</span></span>
<span class="line"><span>-&gt; Skopiuj Refresh Token ze strony callback</span></span>
<span class="line"><span>-&gt; Wklej go z powrotem w ImgBed i zapisz</span></span></code></pre></div><h2 id="referencje" tabindex="-1">Referencje <a class="header-anchor" href="#referencje" aria-label="Permalink to &quot;Referencje&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const j=n(c,[["render",k]]);export{g as __pageData,j as default};
